  return (
    <html>
      <head>
        <title>Test</title>
      </head>
      <body>
        <Loading fallback={<span>Wait</span>}>
          <LazyRoute />
        </Loading>
        {/* rendered at the ROOT, AFTER the pending boundary */}
        <LazyFooter />
